import { Flashcard } from './ib-flashcard-data';
export const PE_FLASHCARDS: Flashcard[] = [
// ═══ LBO MECHANICS (100) ═══
{q:"What is a leveraged buyout?",a:"PE sponsor acquires a company using significant debt, contributes equity, uses target's cash flows to repay debt, and exits at higher equity value.",category:"LBO",difficulty:"Intermediate"},
{q:"What are the main drivers of LBO returns?",a:"Entry multiple, leverage amount, EBITDA growth, FCF for debt paydown, exit multiple, holding period.",category:"LBO",difficulty:"Advanced"},
{q:"Walk through a paper LBO.",a:"Entry: 8x $100M EBITDA = $800M EV. 5x debt ($500M), $300M equity. EBITDA grows to $130M, debt to $250M. Exit 8x = $1,040M. Equity = $790M. ~2.6x MOIC.",category:"LBO",difficulty:"Advanced"},
{q:"What are the three sources of LBO value creation?",a:"1) EBITDA growth (revenue + margin), 2) Debt paydown (deleveraging), 3) Multiple expansion.",category:"LBO",difficulty:"Advanced"},
{q:"What is IRR?",a:"Annualized return equating initial equity to future proceeds. The primary PE return metric.",category:"LBO",difficulty:"Intermediate"},
{q:"What is MOIC?",a:"Multiple of Invested Capital = Exit Equity / Entry Equity. 3x = tripled your money.",category:"LBO",difficulty:"Intermediate"},
{q:"How does holding period affect IRR vs MOIC?",a:"Same MOIC over shorter time = higher IRR. Longer hold may achieve higher MOIC but lower IRR.",category:"LBO",difficulty:"Intermediate"},
{q:"What makes a good LBO candidate?",a:"Stable/predictable cash flows, defensible position, low CapEx, manageable WC, operational improvement potential, assets for debt support.",category:"LBO",difficulty:"Advanced"},
{q:"What makes a bad LBO candidate?",a:"Volatile earnings, heavy cyclicality, massive CapEx, negative FCF, customer concentration, regulatory risk, no improvement levers.",category:"LBO",difficulty:"Advanced"},
{q:"Why do PE firms use leverage?",a:"Debt is cheaper than equity, reduces equity check, magnifies returns. But increases risk and distress probability.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a sources and uses table?",a:"Sources: equity, debt tranches, rollover. Uses: equity purchase, refinancing, fees. Must balance.",category:"LBO",difficulty:"Intermediate"},
{q:"What are common LBO debt instruments?",a:"Revolver, TLA, TLB, senior secured notes, unsecured notes, subordinated debt, mezzanine.",category:"LBO",difficulty:"Advanced"},
{q:"Difference between Term Loan A and B?",a:"TLA: amortizing, lower spread, bank-held. TLB: minimal amortization (1%/yr), higher spread, institutional investors.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a revolver?",a:"Committed credit facility drawn/repaid as needed. Like a corporate credit card. Usually undrawn at close.",category:"LBO",difficulty:"Intermediate"},
{q:"What is mezzanine debt?",a:"Subordinated, 12-20% interest, sometimes with equity warrants. Between senior debt and equity in priority.",category:"LBO",difficulty:"Intermediate"},
{q:"What typical leverage do LBOs use?",a:"4-6x Debt/EBITDA. Higher for stable businesses, lower for cyclical. Market-dependent.",category:"LBO",difficulty:"Advanced"},
{q:"What is a debt covenant?",a:"Contractual restriction. Maintenance: ongoing compliance tests. Incurrence: restrict certain actions.",category:"LBO",difficulty:"Intermediate"},
{q:"What happens if covenants are breached?",a:"Technical default. Lender can accelerate, demand repayment, or negotiate waiver (usually with fees).",category:"LBO",difficulty:"Intermediate"},
{q:"What is covenant-lite?",a:"Incurrence-only covenants. More borrower flexibility, less lender protection. Common in strong credit markets.",category:"LBO",difficulty:"Intermediate"},
{q:"What is interest coverage ratio?",a:"EBITDA / Interest. Measures ability to service debt. Lenders want >2.0x.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a cash sweep?",a:"Mandatory debt repayment from excess FCF. Accelerates deleveraging when cash flow is strong.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a dividend recapitalization?",a:"Portfolio company issues new debt to pay sponsor a special dividend. Returns capital before exit.",category:"LBO",difficulty:"Intermediate"},
{q:"What is PIK interest?",a:"Payment-in-Kind: interest accrues/compounds instead of cash payment. Preserves cash but grows total debt.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a management rollover?",a:"Management reinvests equity in the new deal. Aligns incentives with sponsor.",category:"LBO",difficulty:"Intermediate"},
{q:"What is an equity co-invest?",a:"LPs invest directly alongside the fund in a deal, often with lower fees/carry.",category:"LBO",difficulty:"Intermediate"},
{q:"What happens if exit multiple drops 1x?",a:"IRR/MOIC decrease materially. Entry discipline and EBITDA growth buffer against multiple compression.",category:"LBO",difficulty:"Intermediate"},
{q:"How do you calculate exit equity value?",a:"Exit EV (Exit EBITDA × Exit Multiple) minus net debt at exit.",category:"LBO",difficulty:"Intermediate"},
{q:"LBO vs DCF valuation?",a:"DCF = intrinsic value from cash flows. LBO = what a sponsor can pay given return requirements. Often a valuation floor.",category:"LBO",difficulty:"Advanced"},
{q:"Why might strategics outbid sponsors?",a:"Synergies increase target value for strategics. Sponsors are constrained by return thresholds and debt capacity.",category:"LBO",difficulty:"Intermediate"},
{q:"What is purchase price as multiple of EBITDA?",a:"Entry EV / EBITDA. Typically 7-12x depending on quality, growth, industry.",category:"LBO",difficulty:"Intermediate"},
{q:"How does working capital affect LBO returns?",a:"Favorable WC releases cash for debt paydown. Unfavorable WC consumes cash, slows deleveraging, hurts IRR.",category:"LBO",difficulty:"Advanced"},
{q:"What is a credit agreement?",a:"Legal document governing loan terms: rate, maturity, covenants, events of default, prepayment.",category:"LBO",difficulty:"Intermediate"},
{q:"First lien vs second lien?",a:"First lien: priority on collateral, lower yield. Second lien: subordinate, higher risk/yield, lower recovery.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a paper LBO?",a:"Simplified LBO done by hand. Tests understanding of sources/uses, cash flow, debt paydown, returns.",category:"LBO",difficulty:"Advanced"},
{q:"What is EBITDA in an LBO context?",a:"The key cash flow proxy for debt capacity and valuation. But must be adjusted for non-recurring items.",category:"LBO",difficulty:"Advanced"},
{q:"What is adjusted EBITDA?",a:"EBITDA plus add-backs for non-recurring items. Must be scrutinized - aggressive add-backs inflate leverage capacity.",category:"LBO",difficulty:"Intermediate"},
{q:"What is minimum cash balance?",a:"Cash the company must maintain for operations. Excess above minimum is available for debt repayment.",category:"LBO",difficulty:"Intermediate"},
{q:"How do you project debt paydown?",a:"Start with mandatory amortization. Add optional paydown from excess FCF (after CapEx, WC, taxes, interest, minimums).",category:"LBO",difficulty:"Intermediate"},
{q:"What is a refinancing in LBO context?",a:"Replacing existing debt with new debt at better terms (lower rate, extended maturity). Can free up cash flow.",category:"LBO",difficulty:"Advanced"},
{q:"What is a recap and why do sponsors do it?",a:"Recapitalization: issue new debt to return capital to sponsors. Reduces equity at risk, boosts IRR if done wisely.",category:"LBO",difficulty:"Intermediate"},
{q:"What is the equity contribution ratio?",a:"Sponsor equity / total sources. Typically 30-50%. Lower = more leverage = higher returns but more risk.",category:"LBO",difficulty:"Intermediate"},
{q:"How does CapEx intensity affect LBO attractiveness?",a:"High CapEx reduces FCF for debt paydown. Low CapEx businesses convert more EBITDA to cash, improving returns.",category:"LBO",difficulty:"Advanced"},
{q:"What is a management incentive plan?",a:"Equity pool (10-20%) for management, vesting over time or on exit. Aligns management with sponsor.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a strip in LBO financing?",a:"Each lender takes a proportional piece of multiple debt tranches. Aligns interests across the capital structure.",category:"LBO",difficulty:"Advanced"},
{q:"What is a flex provision?",a:"Allows arranging banks to adjust pricing/structure of debt if market conditions change before syndication.",category:"LBO",difficulty:"Intermediate"},
{q:"What is original issue discount (OID)?",a:"Debt issued below par (e.g., 98 cents on dollar). Effectively increases yield to the lender.",category:"LBO",difficulty:"Intermediate"},
{q:"What is call protection?",a:"Period during which borrower cannot prepay debt without penalty. Protects lender yield. Common in HY bonds.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a make-whole provision?",a:"Prepayment penalty ensuring lender receives full economic benefit of the loan. Discourages early repayment.",category:"LBO",difficulty:"Intermediate"},
{q:"How do interest rates affect LBO returns?",a:"Higher rates increase interest expense, reduce FCF for paydown, and can compress valuation multiples. Major headwind.",category:"LBO",difficulty:"Advanced"},
{q:"What is a unitranche loan?",a:"Single facility combining senior and subordinated debt from one lender. Simpler structure, often used in middle market.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a delayed draw term loan?",a:"Committed but unfunded term loan drawn later for acquisitions or CapEx. Borrower pays commitment fee.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a leverage ratio test?",a:"Debt/EBITDA covenant. If exceeded, technical default. Key ongoing compliance metric.",category:"LBO",difficulty:"Intermediate"},
{q:"What is fixed charge coverage ratio?",a:"(EBITDA - CapEx) / (Interest + Mandatory Amortization + Taxes). Measures ability to cover all fixed obligations.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a springing covenant?",a:"Only tested if a condition is met (e.g., revolver drawn above a threshold). More borrower-friendly.",category:"LBO",difficulty:"Intermediate"},
{q:"What is excess cash flow sweep percentage?",a:"Typically 50-75% of excess FCF. Steps down as leverage decreases. Accelerates deleveraging.",category:"LBO",difficulty:"Intermediate"},
{q:"How do you sensitize an LBO?",a:"Vary entry multiple, exit multiple, revenue growth, margins, and leverage. Show IRR/MOIC under each scenario.",category:"LBO",difficulty:"Advanced"},
{q:"What is a holding company vs operating company structure?",a:"HoldCo owns OpCo. Debt can be at either level. Structural subordination: HoldCo debt is below OpCo debt.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a carve-out LBO?",a:"Acquiring a division from a larger company. Must separate financials, systems, TSAs. Additional complexity.",category:"LBO",difficulty:"Advanced"},
{q:"What is a take-private LBO?",a:"PE firm acquires a public company, delists it. Requires shareholder vote, premium to market price.",category:"LBO",difficulty:"Advanced"},
{q:"What is a secondary buyout?",a:"One PE firm sells to another PE firm. Increasingly common. Questions about remaining value creation.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a club deal?",a:"Multiple PE firms co-invest in one deal. Shares capital requirements and risk.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a continuation vehicle?",a:"GP rolls portfolio company from old fund into new vehicle. LPs can cash out or re-invest.",category:"LBO",difficulty:"Intermediate"},
{q:"What is rollover equity from management?",a:"Management keeps equity in the new structure. Demonstrates confidence and aligns interests. Tax-efficient.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a stub period in an LBO?",a:"Partial year between close and first full fiscal year end. Must model separately for accurate cash flows.",category:"LBO",difficulty:"Advanced"},
{q:"How do you handle transaction fees in an LBO?",a:"Fees are a use of funds in sources/uses. Typically capitalized and may be amortized or expensed.",category:"LBO",difficulty:"Advanced"},
{q:"What is the difference between gross and net IRR?",a:"Gross: return before management fees/carry. Net: return after fees. LPs care about net IRR.",category:"LBO",difficulty:"Intermediate"},
// ═══ FUND ECONOMICS (60) ═══
{q:"What is a typical PE fund structure?",a:"LPs (~99% capital) + GP (~1%). 10-year life. 5yr investment period + 5yr harvesting. Extensions possible.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is 2 and 20?",a:"2% management fee on committed/invested capital + 20% carried interest on profits above hurdle.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is carried interest?",a:"GP's share of profits (typically 20%) above preferred return. Primary GP incentive.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is preferred return / hurdle rate?",a:"Minimum return (often 8%) LPs receive before GP earns carry. Protects LP returns.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is GP commit?",a:"GP's own capital (1-5% of fund). Skin in the game. Aligns interests with LPs.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is DPI?",a:"Distributions to Paid-In. Realized cash returns. What LPs actually got back.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is TVPI?",a:"Total Value to Paid-In = (Distributions + NAV) / Paid-In. Includes unrealized paper gains.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is RVPI?",a:"Residual Value to Paid-In. Unrealized portion. TVPI = DPI + RVPI.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is the J-curve?",a:"Early years show negative returns (fees + investments before exits). Improves as exits occur.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a clawback?",a:"LPs can reclaim excess carry if later performance drops. Protects against overpayment on early exits.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a capital call?",a:"GP requests LPs fund their commitment. Typically when making an investment.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is dry powder?",a:"Uncommitted capital available to invest. High dry powder = competition for deals.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a vintage year?",a:"Year fund makes first investment. Performance compared across vintages.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a fund-of-funds?",a:"Invests in multiple PE funds. Diversification but adds fee layer.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a secondary transaction?",a:"Buying/selling existing LP interests. Provides liquidity and potential discounts.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a continuation vehicle?",a:"GP rolls asset from old fund to new vehicle. LPs choose cash out or re-invest.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is management fee offset?",a:"Transaction/monitoring fees reduce management fee. Alignment mechanism.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"How is fund life structured?",a:"5yr investment + 5yr harvest + 1-2yr extensions. ~10-12 years total.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is an LPAC?",a:"LP Advisory Committee. Advises GP on conflicts, valuations, fund matters.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"European vs American waterfall?",a:"European: whole-fund basis (LP-friendly). American: deal-by-deal (GP-friendly, with clawback).",category:"Fund Economics",difficulty:"Advanced"},
{q:"What is a catch-up?",a:"After LPs receive preferred return, GP gets 100% of next profits until they 'catch up' to their carry percentage.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a distribution waterfall?",a:"Order of cash distribution: return of capital → preferred return → GP catch-up → carried interest split.",category:"Fund Economics",difficulty:"Advanced"},
{q:"What is committed vs invested capital?",a:"Committed: total pledged. Invested: actually deployed. Fee basis may shift from committed to invested over time.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a subscription line?",a:"Short-term borrowing against LP commitments. Bridges capital calls. Can inflate IRR by delaying equity deployment.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"How do subscription lines affect IRR?",a:"Delay equity deployment → shorter measured hold → higher IRR. Criticized for artificial IRR inflation.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is NAV?",a:"Net Asset Value = fair value of portfolio investments minus liabilities. Updated quarterly.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"How are PE portfolio companies valued?",a:"Fair value using comps, DCF, or recent transactions. Governed by ASC 820. Involves significant judgment.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a GP-led secondary?",a:"GP initiates sale of portfolio assets to a new vehicle. Provides LP liquidity and GP continuation.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is co-investment?",a:"LP invests directly alongside fund in specific deal. Lower/no fees. Larger check for LP.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a side car?",a:"Separate vehicle for a specific co-investment opportunity outside the main fund.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is recycling?",a:"Reinvesting capital from early exits back into new deals within the investment period.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is the investment period?",a:"First 3-5 years when GP actively deploys capital. After this, only follow-ons allowed.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a key person clause?",a:"If named key people leave, fund may suspend investing until resolved. Protects LPs.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a no-fault divorce?",a:"Supermajority of LPs can remove GP without cause. Extreme LP protection mechanism.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is a GP removal provision?",a:"Allows LP supermajority (typically 75-80%) to remove GP for cause (fraud, felony).",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is an investment committee?",a:"GP committee that approves investments. Typically includes founding partners and sector heads.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"How do PE firms fundraise?",a:"Roadshows to LPs (pensions, endowments, SWFs, HNW). Present track record, strategy, team. Can take 12-18 months.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What types of LPs invest in PE?",a:"Pensions, endowments, foundations, sovereign wealth funds, insurance companies, family offices, fund-of-funds.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"Why do LPs invest in PE?",a:"Higher returns than public markets (illiquidity premium), diversification, access to operational value creation.",category:"Fund Economics",difficulty:"Intermediate"},
{q:"What is the PME (Public Market Equivalent)?",a:"Compares PE returns to what LPs would have earned investing in public markets. Measures true alpha.",category:"Fund Economics",difficulty:"Intermediate"},
// ═══ DEAL PROCESS & OPERATIONS (100) ═══
{q:"What is the PE deal process?",a:"Sourcing → screening → preliminary DD → LOI → confirmatory DD → SPA → closing → value creation → exit.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What are common PE exit strategies?",a:"Strategic sale, secondary sale, IPO, dividend recap, management buyout.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a platform vs bolt-on?",a:"Platform: initial large acquisition. Bolt-on: smaller acquisitions integrated into platform for scale.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is buy-and-build?",a:"Acquire platform then make multiple bolt-ons to consolidate industry. Drives scale and multiple arbitrage.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is multiple arbitrage?",a:"Buy at lower multiple, sell at higher one. Often from scale (small cos trade lower than large).",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is operational value creation?",a:"Margin expansion, revenue growth, management upgrades, procurement optimization, technology, process improvement.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a 100-day plan?",a:"GP roadmap for first 100 days: quick wins, management changes, operational priorities, KPI tracking.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a QoE report?",a:"Quality of Earnings: third-party analysis of non-recurring items, adjustments, and sustainable run-rate EBITDA.",category:"Deal Process",difficulty:"Intermediate"},
{q:"IOI vs LOI?",a:"IOI: preliminary non-binding. LOI: more detailed, often with exclusivity.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a management presentation?",a:"Target management presents to buyers. Key for team assessment, strategy evaluation, chemistry.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is vendor due diligence?",a:"Seller-commissioned DD to address issues proactively and speed buyer process.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is stapled financing?",a:"Pre-arranged debt package from seller's advisor. Shows deal is financeable.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a CIM?",a:"Confidential Information Memorandum: detailed document describing target's business, financials, highlights.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a teaser?",a:"One-page anonymous summary sent before NDAs to gauge buyer interest.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a data room?",a:"Virtual repository of documents (financials, contracts, legal, HR) for buyer diligence.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What are reps and warranties?",a:"Seller's assertions about target condition. Breach can trigger indemnification claims.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is R&W insurance?",a:"Covers rep breaches. Allows cleaner exits for sellers. Increasingly standard.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is an escrow?",a:"Portion of purchase price held by third party for post-closing adjustments or claims.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is purchase price adjustment?",a:"Post-closing true-up based on actual WC, cash, debt vs estimated at signing.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is an earnout?",a:"Contingent consideration tied to future milestones. Bridges valuation gaps.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a carve-out?",a:"Acquiring a division. Must separate financials, systems, personnel. Requires TSAs.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a TSA?",a:"Transition Services Agreement: seller provides services (IT, HR, accounting) to carved-out business temporarily.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a take-private?",a:"PE acquires public company, delists it. Premium required. Shareholder vote needed.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a club deal?",a:"Multiple PE firms co-invest. Shares capital and risk.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What are operating partners?",a:"Former executives hired by PE to work with portfolio companies on operational improvements.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is EBITDA add-backs?",a:"Non-recurring items added to reported EBITDA: one-time costs, litigation, owner comp, etc.",category:"Deal Process",difficulty:"Intermediate"},
{q:"Why are add-backs controversial?",a:"Aggressive add-backs inflate EBITDA, justify higher leverage/valuation. Must diligence each one.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What KPIs do PE firms track?",a:"Revenue growth, EBITDA margin, FCF conversion, leverage, customer metrics, retention, CapEx efficiency, WC days.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is proprietary deal flow?",a:"Deals sourced directly without intermediary. Less competition, potentially better pricing.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is an exclusive negotiation?",a:"Buyer has sole negotiating rights for a period. Typically granted via LOI with exclusivity.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a process letter?",a:"Sell-side advisor's letter outlining timeline, bid requirements, and process rules for buyers.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a broad vs targeted auction?",a:"Broad: many potential buyers contacted. Targeted: select group of logical buyers. Trade-off: competition vs confidentiality.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a go-shop provision?",a:"Post-signing period where seller can solicit competing bids. Protects board from duty of care claims.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a breakup fee?",a:"Penalty if deal falls through for certain reasons. Typically 1-3% of deal value.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a reverse breakup fee?",a:"Buyer pays if they can't close (e.g., financing failure). Protects seller.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is material adverse change (MAC)?",a:"Clause allowing buyer to walk away if target's business materially deteriorates between signing and closing.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a non-compete?",a:"Seller agrees not to compete with the business for a specified period/geography after sale.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a working capital peg?",a:"Agreed-upon normalized WC level. Actual WC at close is compared and purchase price adjusted.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is net debt at closing?",a:"Total debt minus cash at close. Usually deducted from enterprise value to get equity purchase price.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a locked box mechanism?",a:"Purchase price fixed at a historical date. No post-closing adjustment. Seller bears WC risk after lock date.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a completion accounts mechanism?",a:"Purchase price adjusted based on actual balance sheet at closing. Standard in US/UK.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is financial due diligence?",a:"Analysis of historical financials, quality of earnings, WC trends, CapEx needs, tax exposures.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is commercial due diligence?",a:"Market analysis, competitive positioning, customer validation, growth opportunity assessment.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is legal due diligence?",a:"Review of contracts, litigation, IP, compliance, regulatory matters, corporate structure.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is operational due diligence?",a:"Assessment of operations, supply chain, technology, workforce, management capabilities.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is tax due diligence?",a:"Review of tax compliance, exposures, NOLs, transfer pricing, structuring opportunities.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is environmental due diligence?",a:"Assessment of environmental liabilities, contamination, regulatory compliance. Critical for industrial assets.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is IT due diligence?",a:"Systems assessment, cybersecurity, tech debt, integration complexity, scalability.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is an add-on acquisition strategy?",a:"Systematic bolt-on program to consolidate fragmented markets. Drives scale, capability, geographic expansion.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a strategic plan in PE context?",a:"Portfolio company roadmap: revenue initiatives, margin improvement, M&A pipeline, org changes, exit preparation.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is board governance in PE?",a:"PE firms typically take board seats, influence strategy, approve major decisions, monitor KPIs, hire/fire management.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a management assessment?",a:"Evaluating existing leadership during DD. Determine who stays, who goes, what gaps need filling.",category:"Deal Process",difficulty:"Intermediate"},
{q:"How do PE firms create value operationally?",a:"Pricing optimization, procurement savings, org redesign, system upgrades, geographic expansion, product development, talent upgrade.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is an exit readiness process?",a:"Preparing portfolio company for sale: clean up financials, resolve issues, build equity story, engage advisors.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a sell-side QoE?",a:"Vendor-initiated quality of earnings to pre-empt buyer concerns and accelerate diligence.",category:"Deal Process",difficulty:"Intermediate"},
{q:"What is a red flag report?",a:"Preliminary DD identifying major issues before full diligence. Helps decide whether to proceed.",category:"Deal Process",difficulty:"Intermediate"},
// ═══ ACCOUNTING & VALUATION (60) ═══
{q:"How do you value a company for an LBO?",a:"EV/EBITDA primary. Also DCF, comps, precedents. LBO valuation = max price sponsor can pay for target IRR.",category:"Valuation",difficulty:"Advanced"},
{q:"What is the difference between EV and equity value?",a:"EV = value of operations to all capital providers. Equity = residual to common shareholders after debt.",category:"Valuation",difficulty:"Intermediate"},
{q:"Enterprise Value formula?",a:"EV = Equity Value + Debt + Preferred + Minority Interest - Cash.",category:"Valuation",difficulty:"Intermediate"},
{q:"Why subtract cash from EV?",a:"Cash is non-operating. An acquirer gets the cash, reducing the effective purchase price of operations.",category:"Valuation",difficulty:"Intermediate"},
{q:"Walk through a DCF.",a:"Project UFCF 5-10 years → discount at WACC → terminal value → sum PV → EV → bridge to equity value.",category:"Valuation",difficulty:"Advanced"},
{q:"What is UFCF?",a:"EBIT(1-T) + D&A - CapEx - ΔWC. Cash from operations after tax and reinvestment, before financing.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is WACC?",a:"Weighted cost of equity + after-tax cost of debt, weighted by market cap structure. Discount rate for UFCF.",category:"Valuation",difficulty:"Advanced"},
{q:"What is terminal value?",a:"Value beyond forecast period. Gordon Growth: FCF(1+g)/(WACC-g). Or Exit Multiple: EBITDA × multiple.",category:"Valuation",difficulty:"Advanced"},
{q:"Why does terminal value dominate most DCFs?",a:"Explicit forecast is only 5-10 years. Business assumed to operate indefinitely. Terminal captures remaining value.",category:"Valuation",difficulty:"Advanced"},
{q:"What is EV/EBITDA?",a:"Enterprise Value / EBITDA. Capital-structure neutral multiple. Most common for comparing companies.",category:"Valuation",difficulty:"Intermediate"},
{q:"Why is P/E less useful than EV/EBITDA?",a:"P/E is affected by leverage, taxes, non-operating items. EV/EBITDA is cleaner for comparison.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is a precedent transaction analysis?",a:"Valuation based on multiples paid in past M&A deals for similar companies. Reflects control premium.",category:"Valuation",difficulty:"Advanced"},
{q:"Walk through the three statements.",a:"IS: revenue → expenses → NI. CFS: NI → adjustments → cash change. BS: A = L + E. NI links to RE and CFO.",category:"Valuation",difficulty:"Advanced"},
{q:"If depreciation increases by $10 (25% tax), walk through statements.",a:"IS: EBIT -10, tax -2.5, NI -7.5. CFS: NI -7.5, add back 10 D&A, cash +2.5. BS: cash +2.5, PP&E -10, RE -7.5.",category:"Valuation",difficulty:"Advanced"},
{q:"Why does depreciation increase cash flow?",a:"Non-cash expense creates tax shield. Reduces taxes while being added back on CFS. Net effect = tax savings.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is working capital?",a:"Current operating assets - current operating liabilities. Cash tied up in day-to-day operations.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is goodwill in an acquisition?",a:"Purchase price minus fair value of identifiable net assets. Reflects synergies, brand, premium paid.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is purchase price allocation?",a:"Allocating purchase price to acquired assets/liabilities at fair value, creating intangibles and goodwill.",category:"Valuation",difficulty:"Intermediate"},
{q:"How does PPA affect post-deal earnings?",a:"Asset step-ups create higher D&A and amortization, reducing reported earnings. Can impact accretion/dilution.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is accretion/dilution?",a:"Whether a deal increases (accretive) or decreases (dilutive) acquirer's EPS.",category:"Valuation",difficulty:"Advanced"},
{q:"What makes a deal accretive?",a:"Target's lower P/E than buyer (stock deal), cheap financing, high synergies, limited purchase accounting charges.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is a sum-of-the-parts valuation?",a:"Value each business segment separately with appropriate multiples, then sum. Useful for diversified companies.",category:"Valuation",difficulty:"Intermediate"},
{q:"What is comparable company analysis?",a:"Value target by comparing to publicly traded peers using EV/EBITDA, P/E, and other multiples.",category:"Valuation",difficulty:"Intermediate"},
{q:"How do you select comparable companies?",a:"Match on business model, end markets, growth, margins, size, capital intensity. No comp set is perfect.",category:"Valuation",difficulty:"Intermediate"},
{q:"Forward vs trailing multiples?",a:"Forward (NTM) more relevant - markets price expectations. Trailing (LTM) shows historical.",category:"Valuation",difficulty:"Intermediate"},
// ═══ BEHAVIORAL (80) ═══
{q:"Why private equity?",a:"Ownership, operational value creation, long-term horizon, analytical depth, accountability for returns.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Why not stay in banking?",a:"PE offers ownership, operational involvement, longer-term thinking, seeing value creation through.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Why our firm specifically?",a:"Reference sector focus, fund size, style, portfolio companies, people you've met. Be specific.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What PE deal have you followed?",a:"Know sponsor, target, rationale, entry multiple, leverage, value creation thesis, risks.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about yourself.",a:"Narrative: roles → skills built → why PE is natural next step. Not a bullet-point resume recitation.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Walk me through your resume.",a:"Chronological story: what you learned, how experiences connect, why they point to PE.",category:"Behavioral",difficulty:"Advanced"},
{q:"Tell me about a time with incomplete data.",a:"STAR. Identify key variables, make assumptions, deliver recommendation, acknowledge uncertainty.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What makes a great PE investor?",a:"Pattern recognition, operational intuition, price discipline, management evaluation, comfort with ambiguity.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What industry would you focus on?",a:"Pick one genuinely. Know dynamics, key players, deal activity, why PE is active there.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about your modeling experience.",a:"Most complex model: what it modeled, key assumptions, outputs, challenges, what you learned.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What is your investment style?",a:"Quality vs value, sector focus, growth vs mature, operational vs financial engineering. Show thoughtfulness.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a time you persuaded someone.",a:"Logical argument, listening, adapting approach, reaching alignment through evidence.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you prioritize when overwhelmed?",a:"Highest-impact items first, communicate proactively, delegate, maintain quality on critical tasks.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What would you do in first 30 days?",a:"Learn portfolio, understand team, study active deals, build relationships, identify how to add value.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a mistake and lesson.",a:"Honest, specific. Show self-awareness, what changed, how lesson improved your work.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you evaluate a management team?",a:"Track record, strategic clarity, execution ability, culture, incentive alignment, succession depth.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What makes a good board member?",a:"Strategic guidance, accountability, network, governance, challenging management constructively.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a time you showed leadership.",a:"Initiative, ownership, influence without authority, results. Banking to PE leadership is often 'leading up.'",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you handle disagreement with a senior?",a:"Present reasoning with evidence, listen to their perspective, defer appropriately, but don't be a pushover.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What is your biggest accomplishment?",a:"Real stakes, clear action, measurable impact. Tie to skills relevant for PE.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Why should we hire you over other candidates?",a:"Specific skills, relevant experience, cultural fit, genuine passion. Not generic 'I work hard.'",category:"Behavioral",difficulty:"Intermediate"},
{q:"What do you read to stay informed?",a:"WSJ, Bloomberg, PE Hub, Pitchbook, industry publications, earnings calls. Show genuine daily habit.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a time you worked in a team.",a:"Role clarity, collaboration, handling disagreements, delivering results together.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Where do you see yourself in 5-10 years?",a:"Show ambition: principal/partner track, or building on PE skills. Express commitment to learning first.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a deal you worked on in banking.",a:"Know it cold: client, situation, your role, analysis, outcome. Show what you contributed specifically.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What is the hardest part of PE?",a:"Honest answers: uncertainty of outcomes, responsibility for capital, managing underperforming companies, time pressure.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you handle a portfolio company that's struggling?",a:"Diagnose root cause, assess management, consider operational changes, evaluate strategic alternatives, maintain transparency with LPs.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What questions do you have for us?",a:"Ask about deal flow, team structure, portfolio company involvement, culture, what success looks like. Show curiosity.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a time you went above and beyond.",a:"Specific example showing initiative, not just working late. Added value beyond what was asked.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you build relationships with management teams?",a:"Trust through competence, transparency, follow-through. Be helpful, not just demanding. Earn respect.",category:"Behavioral",difficulty:"Intermediate"},
// ═══ DEAL WALKTHROUGH (from documents) ═══
{q:"Walk me through your deal.",a:"Structure: buy-side/sell-side, industry, business model, your role (modeling/analysis), investment thesis, key value drivers, main risks. Keep it concise - 2 minutes max. Show you understood the WHY, not just the WHAT.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What was the company's business model?",a:"Explain how it generates revenue (subscription, contracts, one-time sales), the recurring vs non-recurring mix, margin drivers, and why the model is attractive (predictability, scalability, capital efficiency).",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What were the key revenue drivers?",a:"Revenue driven by combination of volume, pricing, and customer growth. Identify which driver had the largest impact and why. Show you understood the unit economics.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What were the major cost drivers?",a:"COGS, labor, input costs. Identify the most impactful cost and how it affected margins. Discuss whether costs were fixed or variable and the operating leverage implications.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"Why was this deal happening?",a:"Seller motivations: exit, raise capital, strategic shift, founder retirement. Buyer motivations: growth potential, synergies, platform expansion, undervaluation. Explain both sides.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What was your role on the deal?",a:"Be specific: built the LBO/DCF/comps model, analyzed key sensitivities, conducted industry research, supported due diligence. Quantify where possible.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What did you personally contribute?",a:"Built and stress-tested financial models, identified key sensitivities, evaluated downside scenarios. Show ownership - what did YOUR analysis specifically inform?",category:"Deal Experience",difficulty:"Intermediate"},
{q:"How did your work impact the deal?",a:"Your analysis highlighted a specific risk or opportunity that influenced pricing, structure, or the go/no-go decision. Be concrete.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What assumptions mattered most in your model?",a:"Revenue growth and margin assumptions were most critical - small changes significantly impacted valuation and returns. Terminal value assumptions also highly sensitive.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What sensitivities did you run?",a:"Tested changes in revenue growth, margins, exit multiple, and leverage to understand how returns varied. Identified which inputs had the most impact on IRR/MOIC.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What was the biggest risk to your model?",a:"Overestimating growth or synergies, which would lead to lower-than-expected returns. Also interest rate risk on floating rate debt.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What would make this a bad investment?",a:"Overpaying, poor execution on value creation plan, unexpected industry decline, customer concentration loss, or inability to service debt.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What would make this a great investment?",a:"Strong execution, growth acceleration beyond base case, margin expansion, favorable exit environment, and rapid deleveraging.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What would you monitor post-close?",a:"Revenue growth, EBITDA margins, cash flow conversion, debt paydown, key customer retention, management KPIs, and covenant compliance.",category:"Deal Experience",difficulty:"Intermediate"},
// ═══ LBO DEEP DIVE (from documents) ═══
{q:"What is entry multiple?",a:"The valuation multiple (usually EV/EBITDA) paid to acquire the company. Lower entry = better returns, all else equal.",category:"LBO",difficulty:"Intermediate"},
{q:"What is exit multiple?",a:"The multiple applied when selling the company at exit. Difference between entry and exit = multiple expansion or contraction.",category:"LBO",difficulty:"Intermediate"},
{q:"Why is assuming same entry and exit multiple conservative?",a:"It isolates returns driven by operations (EBITDA growth + deleveraging) rather than relying on market timing or multiple expansion, which is less controllable.",category:"LBO",difficulty:"Advanced"},
{q:"What is sponsor equity in an LBO?",a:"The portion of the purchase price funded by the PE firm's capital (vs debt). Typically 30-50% of total deal value. This is the capital at risk.",category:"LBO",difficulty:"Intermediate"},
{q:"What is a cash flow sweep?",a:"Using excess cash flow above a threshold to mandatorily pay down debt each year. Accelerates deleveraging but reduces financial flexibility.",category:"LBO",difficulty:"Intermediate"},
{q:"Why is free cash flow more important than net income in LBOs?",a:"Debt repayment depends on actual cash generation, not accounting profits. FCF reflects real ability to service and pay down leverage.",category:"LBO",difficulty:"Intermediate"},
{q:"What would make you walk away from an LBO?",a:"Unstable cash flows, excessive valuation, weak management, high customer concentration, or inability to underwrite realistic downside protection.",category:"LBO",difficulty:"Advanced"},
{q:"How do interest rates impact LBOs?",a:"Higher rates increase debt cost, reducing FCF for paydown, lowering achievable leverage, and compressing returns. Also reduce deal activity overall.",category:"LBO",difficulty:"Intermediate"},
{q:"What increases IRR the most?",a:"Strong EBITDA growth combined with rapid debt paydown and a shorter holding period. IRR is very sensitive to timing - faster exits amplify returns.",category:"LBO",difficulty:"Advanced"},
{q:"Why is IRR sensitive to timing?",a:"Because IRR is an annualized return. The same MOIC achieved in 3 years vs 7 years produces dramatically different IRRs. Speed of value creation matters.",category:"LBO",difficulty:"Advanced"},
{q:"What is exit equity value?",a:"Enterprise value at exit minus remaining net debt. This is what the sponsor receives and is used to calculate MOIC and IRR.",category:"LBO",difficulty:"Intermediate"},
// ═══ INVESTMENT THINKING (from documents) ═══
{q:"How do you evaluate whether a business is a good investment?",a:"Start with fundamentals: revenue growth, margins, cash flow. Then assess durability: competitive advantages, customer stickiness, industry structure. Finally evaluate valuation and downside risk for margin of safety.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What makes a business high quality?",a:"Predictable cash flows, strong margins, low capital intensity, and a defensible competitive position that sustains performance over time.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is a margin of safety?",a:"Buying an asset at a price below intrinsic value to protect against errors in assumptions or unexpected downside. Core concept from value investing.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is pricing power and why does it matter?",a:"Ability to raise prices without losing customers. Supports margins, protects against inflation, and indicates competitive strength. One of the most valuable business qualities.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is customer concentration risk?",a:"When a large portion of revenue comes from a few customers. Losing one can severely impact the business. PE firms typically want no single customer >15-20% of revenue.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is a fragmented market and why is it attractive for PE?",a:"Many small competitors with no dominant player. Attractive because it enables consolidation (roll-up) strategies to build scale, drive synergies, and potentially achieve multiple expansion.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is a moat?",a:"A sustainable competitive advantage that protects a company from competitors. Examples: brand, network effects, switching costs, regulatory barriers, cost advantages, proprietary technology.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is switching cost and why is it valuable?",a:"Difficulty or expense for customers to change providers. Creates retention, recurring revenue, and pricing power. Common in software, financial services, and enterprise products.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is recurring revenue and why is it attractive?",a:"Predictable, repeatable revenue (subscriptions, contracts, maintenance). Improves visibility, reduces risk, supports higher valuations, and makes cash flows more suitable for leverage.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"Why is capital intensity important in PE?",a:"High capital requirements reduce free cash flow, limit debt repayment capacity, and increase risk. PE prefers asset-light businesses that convert EBITDA to cash efficiently.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is operating leverage?",a:"When a business has high fixed costs, incremental revenue drops to the bottom line at high margins. Makes profitability scale rapidly with growth, but also amplifies downside.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What is multiple contraction risk?",a:"Risk that the exit multiple is lower than entry multiple. Even with strong operations, lower multiples at exit reduce returns. Mitigate by focusing on operational value creation.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What is margin compression?",a:"Declining profitability, typically from competition, rising costs, or pricing pressure. A major risk factor in PE investments that can erode returns.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is a roll-up strategy?",a:"Acquiring multiple smaller companies in a fragmented market to build a larger platform. Drives scale, cost synergies, and can achieve multiple arbitrage (buy at 5x, platform trades at 8x).",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What risks exist in roll-ups?",a:"Integration challenges, overpaying for add-ons, cultural clashes, management distraction, and the risk that synergies don't materialize as expected.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"Would you invest in a declining industry with strong cash flow?",a:"Potentially yes if cash flows are stable and valuation is attractive (high FCF yield). But must be cautious about long-term sustainability and exit risk.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What's worse: overpaying or missing a deal?",a:"Overpaying, because it permanently impacts returns. You can always find another deal, but you can't undo a bad entry price. Discipline on valuation is critical.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is organic vs inorganic growth?",a:"Organic = internal growth (new customers, pricing, expansion). Inorganic = growth through acquisitions. Organic is more sustainable; inorganic can accelerate but carries integration risk.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is your investment philosophy?",a:"Focus on strong businesses with predictable cash flows, conservative assumptions, and downside protection. Buy quality at reasonable prices rather than mediocre businesses cheaply.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"If you could only look at one metric, what would it be?",a:"Free cash flow, because it reflects real value creation - actual cash generated after all expenses and reinvestment. Unlike net income, it can't be manipulated by accounting choices.",category:"Investment Thinking",difficulty:"Advanced"},
// ═══ MARKETS & INDUSTRY (from documents) ═══
{q:"How do interest rates impact private equity?",a:"Higher rates increase cost of debt, reduce leverage capacity, lower returns, and slow deal activity. Also compress valuation multiples through higher discount rates.",category:"Markets",difficulty:"Intermediate"},
{q:"How does inflation affect portfolio companies?",a:"Raises input costs, compressing margins unless the company has pricing power. Companies with strong brands or contractual escalators are better positioned.",category:"Markets",difficulty:"Intermediate"},
{q:"What is a cyclical vs defensive business?",a:"Cyclical = performance fluctuates with the economy (retail, travel). Defensive = stable demand regardless of conditions (healthcare, utilities). PE prefers defensive for leverage safety.",category:"Markets",difficulty:"Intermediate"},
{q:"What is dry powder?",a:"Capital committed to PE funds but not yet invested. High dry powder = strong future deal competition and potential for elevated valuations.",category:"Markets",difficulty:"Intermediate"},
{q:"What is a tightening credit market?",a:"Lenders become more restrictive, reducing available debt financing. Results in lower leverage, smaller deals, and more equity required - compressing returns.",category:"Markets",difficulty:"Intermediate"},
{q:"What is a secular trend and why is it attractive?",a:"Long-term structural change (digitalization, aging population, sustainability). Secular trends provide durable growth tailwinds independent of economic cycles.",category:"Markets",difficulty:"Intermediate"},
{q:"What is network effect?",a:"Value increases as more users join the platform. Creates powerful competitive advantages and high barriers to entry. Examples: marketplaces, social networks, payment systems.",category:"Markets",difficulty:"Intermediate"},
{q:"What is churn and why does it matter?",a:"Customer loss rate. High churn reduces revenue stability, increases acquisition costs, and lowers lifetime value. Key metric for subscription and recurring revenue businesses.",category:"Markets",difficulty:"Intermediate"},
{q:"What is LTV/CAC and why is it important?",a:"Lifetime Value divided by Customer Acquisition Cost. Measures unit economics - whether each customer is worth more than it costs to acquire. Target: >3x LTV/CAC.",category:"Markets",difficulty:"Advanced"},
{q:"What is demand elasticity?",a:"Sensitivity of demand to price changes. Inelastic demand (necessities) allows pricing power. Elastic demand (luxuries) means price increases lose customers.",category:"Markets",difficulty:"Advanced"},
{q:"What is vertical integration?",a:"Owning different parts of the supply chain (e.g., a retailer manufacturing its own products). Can improve margins and reduce supplier dependency but adds complexity.",category:"Markets",difficulty:"Intermediate"},
{q:"What is commoditization risk?",a:"Products becoming interchangeable, leading to price-based competition and margin erosion. Avoid by investing in differentiated businesses with brand or technology advantages.",category:"Markets",difficulty:"Intermediate"},
// ═══ BEHAVIORAL / FIT (from documents) ═══
{q:"Why investing vs operating?",a:"Interested in evaluating and selecting opportunities across businesses rather than executing within one company. Investing develops pattern recognition and judgment across industries.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What makes a good investor?",a:"Judgment, discipline, analytical rigor, ability to assess risk honestly, willingness to be contrarian when the data supports it, and humility to admit when wrong.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you make decisions with incomplete information?",a:"Identify what I know vs don't know, focus on the 2-3 factors that matter most, make reasonable assumptions, decide, and plan to adjust as new information emerges.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you handle uncertainty?",a:"Build margin of safety, stress-test assumptions, plan for downside scenarios, and maintain flexibility to adjust. Accept that uncertainty is inherent - manage it, don't avoid it.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What motivates you?",a:"Continuous improvement, developing strong judgment, and being in environments where the quality of my thinking directly impacts outcomes.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What would you do if your investment thesis is wrong?",a:"Reassess quickly and honestly. Identify what changed or what I missed. Determine whether it's a temporary issue or a fundamental thesis break. Avoid anchoring to a losing position.",category:"Behavioral",difficulty:"Advanced"},
{q:"What differentiates you from other candidates?",a:"Focus on the 'why' behind decisions, not just mechanics. Think like an investor rather than just an analyst. Combine technical rigor with genuine intellectual curiosity about businesses.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What concerns you about PE?",a:"The responsibility of making high-stakes decisions with other people's capital. But that's also what makes it compelling - the weight of the decisions forces discipline and growth.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you stay informed on markets and deals?",a:"WSJ, FT, Bloomberg, industry reports, earnings calls, deal announcements. Build a daily habit of reading and forming views rather than cramming before interviews.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What is the biggest risk in PE?",a:"Permanent capital loss from poor assumptions, overleverage, or deteriorating fundamentals. Unlike public markets, you can't easily exit a bad PE investment.",category:"Behavioral",difficulty:"Advanced"},
// ═══ DEAL WALKTHROUGH - ADVANCED (from documents) ═══
{q:"What was the weakest part of your deal and how did you think about it?",a:"Identify a real weakness (customer concentration, aggressive assumptions, thin margins). Explain how you stress-tested it and whether the deal still held under conservative scenarios.",category:"Deal Experience",difficulty:"Advanced"},
{q:"How did you determine if management's projections were realistic?",a:"Compared projections to historical performance, industry growth rates, and underlying unit economics. If assumptions exceeded benchmarks significantly, built a separate downside case.",category:"Deal Experience",difficulty:"Advanced"},
{q:"If you had to pitch your deal in one sentence, what would you say?",a:"Structure: 'A business with [core strength], valued at [multiple], with upside from [driver] and manageable risk around [key risk].' Practice until it's crisp.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What was the most important diligence question in your deal?",a:"Whether the company's growth was sustainable or driven by one-time factors, since that directly determined whether valuation was justified.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What would you have done differently in your analysis?",a:"Be specific: 'I would have been more conservative on [growth/margins] and spent more time on [customer interviews/competitive analysis].' Shows self-awareness.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"How did you evaluate whether the company had pricing power?",a:"Analyzed historical price increases vs volume changes, customer retention after increases, competitive alternatives, and switching costs.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What would cause your investment thesis to break?",a:"Identify the 1-2 things that must hold true: sustained demand, key customer retention, margin stability. If those break, the deal doesn't work regardless of other factors.",category:"Deal Experience",difficulty:"Advanced"},
{q:"How did you think about exit opportunities?",a:"Considered likely buyer universe (strategics vs sponsors), comparable precedent exits, and whether the business would remain attractive 3-5 years out.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What was the biggest disconnect between buyers and sellers?",a:"Typically valuation expectations - sellers anchor to best-case projections while buyers underwrite conservative cases. Also disagreements on normalizing adjustments to EBITDA.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What would make you increase your bid?",a:"Stronger conviction in growth sustainability, discovery of additional synergies, or competitive pressure in the process requiring higher pricing to win.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What would make you lower your bid?",a:"Higher perceived risk uncovered in diligence, weaker fundamentals than presented, customer concentration, or unreliable management projections.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What was the least reliable part of your model?",a:"Long-term growth assumptions - inherently uncertain and highly sensitive. Also terminal value assumptions in a DCF.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"How would you explain your deal to a non-finance person?",a:"We evaluated whether buying this company at a certain price would generate a strong return based on its ability to grow profits and pay down the debt used to buy it.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What part of your deal required the most judgment rather than analysis?",a:"Assessing whether growth was structural or temporary. Data showed strong performance, but judgment was needed to determine if it was repeatable.",category:"Deal Experience",difficulty:"Advanced"},
{q:"How did you distinguish between a good company and a good investment?",a:"A good company has strong fundamentals, but a good investment also depends on valuation and entry price. Great businesses can be bad investments if you overpay.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What was the most debated point in your deal?",a:"Sustainability of margins - small changes had outsized impact on valuation and returns. The team debated whether current margins were normalized.",category:"Deal Experience",difficulty:"Advanced"},
{q:"If you had unlimited time, what additional diligence would you do?",a:"Deeper customer analysis - retention by cohort, pricing sensitivity, switching behavior, and long-term demand trends. Also more competitive intelligence.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"How did you validate your assumptions?",a:"Cross-referenced with historical performance, industry benchmarks, third-party data, management interviews, and customer reference calls.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"How would your view change if the company missed projections by 10%?",a:"Significantly reduce returns and potentially invalidate the thesis if leverage is high. Would reassess whether the miss is one-time or indicative of a trend.",category:"Deal Experience",difficulty:"Advanced"},
{q:"What was the most important qualitative factor in your deal?",a:"Management quality - because execution drives outcomes. A great plan with weak management underperforms; a decent plan with strong management often overdelivers.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"How did you get comfortable with the industry?",a:"Reviewed industry reports, competitor filings, expert interviews, and key trend data. Built a view on growth, cyclicality, and competitive dynamics.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What assumption did you disagree with in your deal?",a:"Growth assumptions above industry averages. I tested more conservative scenarios and showed how returns changed - this influenced the team's pricing view.",category:"Deal Experience",difficulty:"Advanced"},
{q:"How did you decide which comps to use?",a:"Selected companies with similar business models, end markets, size, growth profiles, and margin structures. Excluded outliers and explained why.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What was the most important output of your model?",a:"The return profile - IRR and MOIC under base, upside, and downside cases. Also sensitivity tables showing which inputs mattered most.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"How did you check if your model made sense?",a:"Compared outputs to industry benchmarks, checked internal consistency (BS balances, cash flow ties), and sanity-checked implied growth rates and margins.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What operational improvement did you identify?",a:"Specific example: procurement optimization, SG&A reduction, pricing adjustments, or technology investment that could improve margins by a quantifiable amount.",category:"Deal Experience",difficulty:"Intermediate"},
{q:"What would you prioritize first after acquiring the company?",a:"Stabilizing operations, ensuring strong cash flow generation, assessing management capability, and implementing quick-win operational improvements.",category:"Deal Experience",difficulty:"Intermediate"},
// ═══ LBO / TECHNICAL - ADVANCED (from documents) ═══
{q:"What happens to IRR if you double the holding period but keep MOIC constant?",a:"IRR decreases significantly. Same 2x return over 3 years = ~26% IRR, over 6 years = ~12% IRR. Time is the biggest IRR driver.",category:"LBO",difficulty:"Advanced"},
{q:"If EBITDA grows but cash flow doesn't, what's happening?",a:"Likely higher capex, working capital consumption, or increased interest expense absorbing the EBITDA growth. Cash flow ≠ EBITDA.",category:"LBO",difficulty:"Advanced"},
{q:"Why might a company have high EBITDA but low LBO returns?",a:"High reinvestment needs (capex, WC), meaning EBITDA doesn't convert to FCF. Also possible if entry multiple was too high or leverage capacity is limited.",category:"LBO",difficulty:"Advanced"},
{q:"What is debt capacity?",a:"The maximum amount of debt a company can support based on cash flow stability, interest coverage, and lender requirements. Determines how much leverage an LBO can use.",category:"LBO",difficulty:"Intermediate"},
{q:"What happens if interest coverage falls too low?",a:"Risks breaching debt covenants, triggering renegotiation, default, or acceleration of debt repayment. Lenders may restrict operations.",category:"LBO",difficulty:"Intermediate"},
{q:"What is the trade-off between leverage and risk?",a:"More leverage increases potential equity returns but also increases probability of financial distress. The optimal level balances return enhancement with downside protection.",category:"LBO",difficulty:"Intermediate"},
{q:"Why might a PE firm choose less leverage than available?",a:"To reduce downside risk, maintain covenant cushion, preserve flexibility for add-on acquisitions, or because the business has some cash flow variability.",category:"LBO",difficulty:"Advanced"},
{q:"What happens if you exit earlier than planned?",a:"IRR increases because returns are realized faster (time value of money). MOIC may be lower if value creation plan isn't fully executed.",category:"LBO",difficulty:"Intermediate"},
{q:"What happens if exit is delayed?",a:"IRR decreases due to time value of money, even if MOIC improves. Delayed exits also increase exposure to market and business risk.",category:"LBO",difficulty:"Intermediate"},
{q:"What is the impact of higher transaction fees on returns?",a:"Increases total uses, requiring more equity or debt. Directly reduces equity returns, especially on smaller deals where fees are proportionally larger.",category:"LBO",difficulty:"Intermediate"},
{q:"Why are management incentives important in LBOs?",a:"They align management with value creation goals - typically through equity co-invest and option pools. Misaligned incentives lead to poor execution.",category:"LBO",difficulty:"Intermediate"},
{q:"What happens if EBITDA declines but debt stays constant?",a:"Leverage ratio increases, covenant pressure builds, and equity value erodes. Can trigger a downward spiral if lenders lose confidence.",category:"LBO",difficulty:"Intermediate"},
{q:"What happens if revenue grows but margins decline in an LBO?",a:"Returns may not improve because profitability per dollar of revenue is weaker. Revenue growth without margin is often value-destructive in leveraged situations.",category:"LBO",difficulty:"Advanced"},
{q:"Why is EBITDA not always a good proxy for cash flow?",a:"Because it ignores capex, working capital changes, taxes actually paid, and one-time items. A company can have high EBITDA but low or negative FCF.",category:"LBO",difficulty:"Intermediate"},
{q:"Why do PE firms model multiple scenarios?",a:"To understand how returns change under different conditions (base/upside/downside). Shows where the deal breaks and what assumptions must hold for acceptable returns.",category:"LBO",difficulty:"Intermediate"},
{q:"What is the benefit of lower entry valuation?",a:"Provides margin of safety, higher potential returns, and more room for error in execution. Entry price is the most controllable return driver.",category:"LBO",difficulty:"Intermediate"},
{q:"What is the impact of higher equity contribution?",a:"Lower leverage reduces risk but may reduce IRR since more capital is at risk. MOIC may be similar but IRR drops due to larger equity base.",category:"LBO",difficulty:"Advanced"},
{q:"Why is debt structured in layers?",a:"Different risk/return profiles for different lenders. Senior secured = lowest risk/rate. Mezz = higher risk/rate. Each layer has different terms, covenants, and priority.",category:"LBO",difficulty:"Intermediate"},
// ═══ INVESTMENT JUDGMENT - ADVANCED (from documents) ═══
{q:"How do you think about asymmetric risk?",a:"Look for situations where upside significantly outweighs downside - where being right earns much more than being wrong costs. Core to value investing.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What is confirmation bias in investing?",a:"The tendency to seek information that supports your thesis while ignoring contradictory evidence. Combat it by actively looking for reasons the deal could fail.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"How do you avoid overfitting your model?",a:"Keep assumptions grounded in reality, avoid unnecessary complexity, use reasonable ranges instead of false precision, and sense-check outputs against benchmarks.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What is more dangerous: overestimating growth or underestimating risk?",a:"Underestimating risk, because it can lead to permanent capital loss. Overestimating growth leads to lower returns; underestimating risk leads to losses.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"How do you think about optionality in investing?",a:"Optionality provides upside beyond the base case (new products, markets, M&A). Valuable but shouldn't be the primary thesis - base case must work standalone.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"What is the biggest red flag in a business?",a:"Unpredictable cash flows, heavy reliance on a single customer/product, or management that can't clearly articulate how they'll create value.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"Would you invest in a business you don't fully understand?",a:"No. Understanding the business is fundamental to assessing risk. If you can't explain how it makes money and what drives it, you can't evaluate downside.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is a 'good enough' investment?",a:"One that meets return targets with acceptable risk, even if it's not perfect. Waiting for perfect deals means never investing. Discipline ≠ paralysis.",category:"Investment Thinking",difficulty:"Advanced"},
{q:"How do you define a 'safe' investment?",a:"One with strong downside protection: stable cash flows, low leverage, defensible position, and realistic assumptions. Safety is about surviving the worst case.",category:"Investment Thinking",difficulty:"Intermediate"},
{q:"What is a strong investment thesis?",a:"A clear, simple explanation of why a business will create value. If you can't explain it in 2-3 sentences, the thesis is probably too complicated or weak.",category:"Investment Thinking",difficulty:"Intermediate"},
// ═══ MARKETS & INDUSTRY - ADDITIONAL (from documents) ═══
{q:"How would a recession impact leveraged companies?",a:"Reduced cash flow makes debt servicing harder, increasing default risk. Companies with variable costs and pricing power fare better than those with fixed cost structures.",category:"Markets",difficulty:"Intermediate"},
{q:"What industries benefit from consolidation?",a:"Fragmented industries with many small players: healthcare services, business services, food distribution, auto repair, dental/vet practices. Scale creates synergies and multiple arbitrage.",category:"Markets",difficulty:"Intermediate"},
{q:"What is a structural vs cyclical trend?",a:"Structural = long-term permanent shift (digitalization, aging demographics). Cyclical = temporary fluctuation tied to economic cycle. Structural trends are far more reliable for investment theses.",category:"Markets",difficulty:"Intermediate"},
{q:"What is an industry tailwind?",a:"A factor that supports growth - rising demand, regulatory changes creating opportunity, technological adoption. Tailwinds make organic growth easier.",category:"Markets",difficulty:"Intermediate"},
{q:"What is an industry headwind?",a:"A factor that slows growth - increased competition, regulatory burden, declining demand, technological disruption. Headwinds require the company to fight harder for results.",category:"Markets",difficulty:"Intermediate"},
// ═══ BEHAVIORAL / FIT - ADDITIONAL (from documents) ═══
{q:"Tell me about a time you had to defend your opinion.",a:"Structured example: state your position, the pushback you received, how you supported your view with data and logic, and the outcome. Show conviction without arrogance.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What do you do when you disagree with someone senior?",a:"Present your perspective respectfully with supporting evidence. Frame it as 'I see it differently because of X' rather than 'you're wrong.' Be willing to be overruled.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you handle repetitive work?",a:"Focus on accuracy and efficiency, understanding that detail work builds reliability and trust. Find ways to improve the process while maintaining quality.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What is something you've done that shows genuine interest in investing?",a:"Independently analyzed companies, built models, followed deals, read investor letters, or managed personal investments. Show authentic curiosity, not just interview prep.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What do you do when you don't know the answer?",a:"Break the problem down, identify what I do know, make logical assumptions, and reason toward an answer. Better than guessing or freezing.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you handle situations where you're wrong?",a:"Acknowledge it quickly, understand what led to the error, learn from it, and adjust my approach. Avoid defensiveness - credibility comes from honesty.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Why will you succeed in private equity?",a:"Combine analytical rigor with genuine intellectual curiosity about businesses, willingness to do the hard work, and a continuous improvement mindset.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What does success look like to you in PE?",a:"Consistently making strong investment decisions, developing better judgment over time, and contributing meaningfully to portfolio company value creation.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What is one skill you've improved recently?",a:"Be specific and honest: financial modeling speed, structuring investment memos, presenting under pressure, or deepening sector knowledge through consistent practice.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What makes you a good fit for PE?",a:"Strong analytical foundation, genuine curiosity about businesses and investing, ability to handle ambiguity, and a work ethic that doesn't require external motivation.",category:"Behavioral",difficulty:"Intermediate"},
];
